#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to find prime factors
void primeFactors(int n, int* factors, int* count) {
    *count = 0;
    for (int i = 2; i * i <= n; i++) {
        while (n % i == 0) {
            factors[*count] = i;
            (*count)++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[*count] = n;
        (*count)++;
    }
}

// Function to generate all combinations of factors
void generateCombinations(int* factors, int count, int a, int b, int c, int* result) {
    int x, y, z;
    for (x = 1; x <= a; x++) {
        for (y = 1; y <= b; y++) {
            for (z = 1; z <= c; z++) {
                if (x * y * z == 1) {
                    int tempCount = count;
                    int tempX = x;
                    int tempY = y;
                    int tempZ = z;
                    for (int i = 0; i < count; i++) {
                        if (tempX % factors[i] == 0) {
                            tempX /= factors[i];
                            tempCount--;
                        } else if (tempY % factors[i] == 0) {
                            tempY /= factors[i];
                            tempCount--;
                        } else if (tempZ % factors[i] == 0) {
                            tempZ /= factors[i];
                            tempCount--;
                        }
                    }
                    if (tempCount == 0 && tempX == 1 && tempY == 1 && tempZ == 1) {
                        (*result)++;
                    }
                }
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, a, b, c;
        scanf("%d %d %d %d", &N, &a, &b, &c);
        int factors[100];
        int count;
        primeFactors(N, factors, &count);
        int result = 0;
        generateCombinations(factors, count, a, b, c, &result);
        printf("%d\n", result);
    }
    return 0;
}

